const crypto = require('crypto');

function safeTrim(value){
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

const item = items[0].json || {};
const body = item.body || {};
const headers = item.headers || {};
const query = item.query || {};

const message = safeTrim(body.message ?? body.text ?? '');
const traceId = safeTrim(headers['x-request-id'] || headers['x-trace-id'] || body.trace_id || query.trace_id || '') || crypto.randomUUID();
const rawSession = safeTrim(body.session_id ?? body.sessionId ?? body.session ?? query.session_id ?? '');
const sessionId = (rawSession || crypto.randomUUID()).replace(/[^a-zA-Z0-9-_:.]/g, '').slice(0, 64) || crypto.randomUUID();

const gtcValue = body.gtc_user_id ?? body?.client?.gtc_user_id ?? null;
const gtcUserId = gtcValue === null || gtcValue === undefined || gtcValue === '' ? null : Number(gtcValue) || null;

const client = {
  user_id: safeTrim(body.user_id ?? body.userId ?? body?.client?.user_id ?? body?.client?.id ?? ''),
  gtc_user_id: gtcUserId,
  email: safeTrim(body.email ?? body?.client?.email ?? ''),
  locale: safeTrim(body.locale ?? body?.client?.locale ?? 'en'),
  timezone: safeTrim(body.timezone ?? body?.client?.timezone ?? ''),
  jwt: safeTrim(body.jwt ?? (headers.authorization || '').replace(/^Bearer\s+/i, '')),
  metadata: body?.client?.metadata ?? null
};

const metadata = Object.assign({}, body.metadata || {});
if (!metadata.page && body.page) metadata.page = body.page;
if (!metadata.user_agent && headers['user-agent']) metadata.user_agent = headers['user-agent'];

let error = null;
if (!message) {
  error = {
    status: 'error',
    code: 'bad_request',
    detail: 'message is required',
    httpStatus: 400
  };
}

return [{
  json: {
    channel: 'web',
    message,
    session_id: sessionId,
    safe_session_id: `web:${sessionId}`,
    metadata,
    client,
    request: {
      headers,
      query,
      ip: safeTrim(headers['x-forwarded-for'] || '').split(',')[0] || item.ip || null,
      user_agent: headers['user-agent'] || null
    },
    trace_id: traceId,
    error
  }
}];

