function sortHistory(items){
  return items.map((it, idx) => {
    const j = it.json || {};
    const t = Date.parse(j.timestamp || '');
    return { j, idx, t: Number.isNaN(t) ? null : t };
  }).sort((a, b) => {
    if (a.t !== null && b.t !== null) return a.t - b.t;
    if (a.t === null && b.t === null) return a.idx - b.idx;
    return a.t === null ? 1 : -1;
  }).map(({ j }) => j);
}

function detectStage(text){
  if (!text) return 'discovery';
  const lower = text.toLowerCase();
  const searchHints = ['price', 'стоимость', 'купить', 'найди', 'where to buy', 'сколько стоит', 'compare', 'search', 'посмотри'];
  const hasSearch = searchHints.some(word => lower.includes(word));
  if (hasSearch) return 'product_search';
  return 'discovery';
}

const history = sortHistory(items);
let prompt = '';
for (const row of history) {
  const ts = row.timestamp ? new Date(row.timestamp).toISOString() : '';
  const msg = row.message?.trim();
  const resp = row.response?.trim();
  if (msg) prompt += `${ts ? `[${ts}] ` : ''}User: ${msg}
`;
  if (resp) prompt += `${ts ? `[${ts}] ` : ''}AI: ${resp}
`;
}

const latestMessage = ($('Normalize Input').item.json.message || '').trim();
const stage = detectStage(latestMessage);
const userData = $('Lookup Web User').item.json || {};
const client = $('Normalize Input').item.json.client || {};
const profile = {
  gtc_user_id: userData.gtc_user_id,
  email: client.email || userData.email,
  locale: client.locale || 'en',
  timezone: client.timezone || null
};

return [{
  json: {
    prompt,
    history_tail: prompt.slice(-1500),
    latest_message: latestMessage,
    stage,
    gtc_user_id: userData.gtc_user_id,
    user_id: userData.user_id,
    session_id: $('Normalize Input').item.json.safe_session_id,
    user_profile: profile
  }
}];

