function stripCodeBlocks(text){
  return String(text || '')
    .replace(/```[\s\S]*?```/g, '')
    .replace(/```/g, '')
    .replace(/<{1}[^>]*>/g, '')
    .trim();
}

function collapseWhitespace(text){
  return text.replace(/
{3,}/g, '

').replace(/[ 	]{2,}/g, ' ');
}

const agent = $json || {};
const output = agent.output || agent.text || '';
const cleaned = collapseWhitespace(stripCodeBlocks(output));
const reply = cleaned || 'I am sorry, I could not generate a response right now.';

const stage = $('Build Prompt').item.json.stage || 'discovery';
const traceId = $('Normalize Input').item.json.trace_id;

const intermediate = Array.isArray(agent.intermediateSteps) ? agent.intermediateSteps : [];
const toolCalls = intermediate.map(step => ({
  tool: step?.action,
  input: step?.inputs || null,
  observation: step?.observation || null
}));

return [{
  json: {
    status: 'ok',
    reply,
    stage,
    suggestions: [],
    trace_id: traceId,
    raw_output: output,
    tool_calls: toolCalls
  }
}];

